CREATE OR ALTER PROCEDURE [SSop].[QuotesUpsert]
	(	@OrganisationalUnitGuid UNIQUEIDENTIFIER,
		@QuotingUserGuid UNIQUEIDENTIFIER,
		@ContractGuid UNIQUEIDENTIFIER,
		@Date DATE,
		@Overview NVARCHAR(MAX),
		@ExpiryDate DATE,
		@DateSent DATE,
		@DateAccepted DATE,
		@DateRejected DATE,
		@RejectionReason NVARCHAR(MAX),
		@FeeCap DECIMAL(19, 2),
		@IsFinal BIT,
		@ExternalReference NVARCHAR(50),
		@QuotingConsultantGuid UNIQUEIDENTIFIER,
		@AppointmentFromRibaStageGuid UNIQUEIDENTIFIER,
		@CurrentStageGuid UNIQUEIDENTIFIER,
		@DeadDate DATE,
		@EnquiryServiceGuid UNIQUEIDENTIFIER,
		@ProjectGuid UNIQUEIDENTIFIER,
		@Guid UNIQUEIDENTIFIER,
		@JobType UNIQUEIDENTIFIER,
		@DeclinedToQuoteReason NVARCHAR(MAX),
		@DescriptionOfWorks NVARCHAR(MAX),
		@ExclusionsAndLimitations NVARCHAR(MAX)
	)
AS
BEGIN
	DECLARE @OrganisationalUnitId		INT = -1,
			@QuotingUserId				INT,
			@ContractId					INT = -1,
			@IsInsert					BIT = 0,
			@QuoteId					INT,
			@QuoteNumber				INT,
			@QuotingConsultantId		INT,
			@AppointmentFromRibaStageId INT,
			@CurrentStageId				INT,
			@EnquiryServiceID			INT,
			@ProjectID					INT,
			@JobTypeId                  INT; --New

	SELECT	@OrganisationalUnitId = ID
	FROM	SCore.OrganisationalUnits
	WHERE	(Guid = @OrganisationalUnitGuid);

	SELECT	@QuotingUserId = ID
	FROM	SCore.Identities
	WHERE	(Guid = @QuotingUserGuid);

	SELECT	@QuotingConsultantId = ID
	FROM	SCore.Identities
	WHERE	(Guid = @QuotingConsultantGuid);

	SELECT	@ContractId = ID
	FROM	SSop.Contracts
	WHERE	(Guid = @ContractGuid);

	SELECT	@AppointmentFromRibaStageId = ID
	FROM	SJob.RibaStages
	WHERE	(Guid = @AppointmentFromRibaStageGuid);

	SELECT	@EnquiryServiceID = es.ID
	FROM	SSop.EnquiryServices AS es
	WHERE	(es.Guid = @EnquiryServiceGuid);

	SELECT	@CurrentStageId = ID
	FROM	SJob.RibaStages
	WHERE	(Guid = @CurrentStageGuid);


	SELECT	@ProjectID = p.ID
	FROM	SSop.Projects AS p
	WHERE	(p.Guid = @ProjectGuid);

	EXEC SCore.UpsertDataObject @Guid = @Guid,					-- uniqueidentifier
								@SchemeName = N'SSop',			-- nvarchar(255)
								@ObjectName = N'Quotes',		-- nvarchar(255)
								@IsInsert = @IsInsert OUTPUT;	-- bit

	IF (@IsInsert = 1)
	BEGIN
		INSERT	SSop.Quotes
			 (RowStatus,
			  Guid,
			  OrganisationalUnitID,
			  QuotingUserId,
			  ContractID,
			  Date,
			  Overview,
			  ExpiryDate,
			  DateSent,
			  DateAccepted,
			  DateRejected,
			  RejectionReason,
			  FeeCap,
			  IsFinal,
			  ExternalReference,
			  QuotingConsultantId,
			  AppointmentFromRibaStageId,
			  CurrentRibaStageId,
			  DeadDate,
			  EnquiryServiceID,
			  ProjectId,
			  DeclinedToQuoteReason,
			  DescriptionOfWorks,
			  ExclusionsAndLimitations)
		VALUES
			 (
				 0,						-- RowStatus - tinyint
				 @Guid,					-- Guid - uniqueidentifier
				 @OrganisationalUnitId, -- OrganisationalUnitID - int
				 @QuotingUserId,		-- QuotingUserId - int
				 @ContractId,			-- ContractID - int
				 @Date,					-- Date - date
				 @Overview,				-- Overview - nvarchar(max)
				 @ExpiryDate,
				 @DateSent,
				 @DateAccepted,
				 @DateRejected,
				 @RejectionReason,
				 @FeeCap,
				 @IsFinal,
				 @ExternalReference,
				 @QuotingConsultantId,
				 @AppointmentFromRibaStageId,
				 @CurrentStageId,
				 @DeadDate,
				 @EnquiryServiceID,
				 @ProjectID,
				 @DeclinedToQuoteReason,
				 @DescriptionOfWorks,
				 @ExclusionsAndLimitations
			 );

		SELECT	@QuoteId = SCOPE_IDENTITY ();

	END;
	ELSE
	BEGIN
		DECLARE @_quotingConsultant INT,
				@_isFinal			BIT,
				@_emailRecipient	NVARCHAR(MAX),
				@_emailBody			NVARCHAR(MAX),
				@_emailSubject		NVARCHAR(MAX),
				@_quoteNumber		NVARCHAR(MAX);

		SELECT	@_quotingConsultant = QuotingConsultantId,
				@_isFinal			= IsFinal,
				@_quoteNumber		= Number
		FROM	SSop.Quotes
		WHERE	(Guid = @Guid);

		UPDATE	SSop.Quotes
		SET		OrganisationalUnitID = @OrganisationalUnitId,
				QuotingUserId = @QuotingUserId,
				ContractID = @ContractId,
				Date = @Date,
				Overview = @Overview,
				ExpiryDate = @ExpiryDate,
				DateSent = @DateSent,
				DateAccepted = @DateAccepted,
				DateRejected = @DateRejected,
				RejectionReason = @RejectionReason,
				FeeCap = @FeeCap,
				IsFinal = @IsFinal,
				ExternalReference = @ExternalReference,
				QuotingConsultantId = @QuotingConsultantId,
				AppointmentFromRibaStageId = @AppointmentFromRibaStageId,
				CurrentRibaStageId = @CurrentStageId,
				DeadDate = @DeadDate,
				EnquiryServiceID = @EnquiryServiceID,
				ProjectId = @ProjectID,
				DeclinedToQuoteReason = @DeclinedToQuoteReason,
				DescriptionOfWorks = @DescriptionOfWorks,
				ExclusionsAndLimitations = @ExclusionsAndLimitations
		WHERE	(Guid = @Guid);

		--Get the ID for the job type
		SELECT @JobTypeId = ID 
		FROM SJob.JobTypes
		Where Guid = @JobType; 


		UPDATE SSop.EnquiryServices
		SET JobTypeId = @JobTypeId
		WHERE (Guid = @EnquiryServiceGuid)


		IF (@QuotingConsultantId <> @_quotingConsultant)
		BEGIN
			SELECT	@_emailRecipient = i.EmailAddress
			FROM	SCore.Identities AS i
			WHERE	(i.ID = @QuotingConsultantId);

			SET @_emailBody = N'You have been assigned as the consultant for quote <a href="'
							  + +SCore.GetCurrentApplicationUrl () + N'/QuoteDetail/' + CONVERT (	NVARCHAR(MAX),
																									@Guid
																								)
							  + N'/%7b%22DataObjectGuid%22%3a%22' + CONVERT (	NVARCHAR(MAX),
																				@Guid
																			)
							  + N'%22%2c%22EntityTypeGuid%22%3a%221c4794c1-f956-4c32-b886-5500ac778a56%22%7d/https%3a%2f%2fbre.socotec.co.uk%3a9602%2f" taget="_blank">'
							  + @_quoteNumber + N'</a>. Please take a moment to review this record.';
			SET @_emailSubject = N'CymBuild: Quote ' + @_quoteNumber + N' assigned to your user.';

			EXEC SAlert.CreateNotification @Recipients = @_emailRecipient,	-- nvarchar(max)
										   @Subject = @_emailSubject,		-- nvarchar(255)
										   @Body = @_emailBody,				-- nvarchar(max)
										   @BodyFormat = N'TEXT',			-- nvarchar(20)
										   @Importance = N'NORMAL';			-- nvarchar(6)
		END;

		IF (@IsFinal <> @_isFinal)
	   AND	(@IsFinal = 1)
	   AND	(@DateSent IS NULL)
		BEGIN
			SELECT	@_emailRecipient = STRING_AGG (	  i.EmailAddress,
													  N';'
												  )
			FROM	SCore.Identities AS i
			JOIN	SCore.UserGroups AS ug ON (ug.IdentityID = i.ID)
			JOIN	SCore.Groups	 AS g ON (g.ID			 = ug.GroupID)
			WHERE	(g.Code = N'CDMSA');

			SET @_emailBody = N'Quote <a href="' + SCore.GetCurrentApplicationUrl () + N'/QuoteDetail/'
							  + CONVERT (	NVARCHAR(MAX),
											@Guid
										) + N'/%7b%22DataObjectGuid%22%3a%22' + CONVERT (	NVARCHAR(MAX),
																							@Guid
																						)
							  + N'%22%2c%22EntityTypeGuid%22%3a%221c4794c1-f956-4c32-b886-5500ac778a56%22%7d/https%3a%2f%2fbre.socotec.co.uk%3a9602%2f" taget="_blank">'
							  + @_quoteNumber
							  + N'</a> has been marked as final. Please review this record and send out the quote.';
			SET @_emailSubject = N'CymBuild: Quote ' + @_quoteNumber + N' ready to send.';

			EXEC SAlert.CreateNotification @Recipients = @_emailRecipient,	-- nvarchar(max)
										   @Subject = @_emailSubject,		-- nvarchar(255)
										   @Body = @_emailBody,				-- nvarchar(max)
										   @BodyFormat = N'TEXT',			-- nvarchar(20)
										   @Importance = N'NORMAL';			-- nvarchar(6)
		END;
	END;

	IF (@IsInsert = 1)
	BEGIN
		SELECT	@QuoteNumber = NEXT VALUE FOR SSop.QuoteNumber;

		UPDATE	SSop.Quotes
		SET		Number = @QuoteNumber,
				RowStatus = 1
		WHERE	(ID = @QuoteId);
	END;

	/* Tempoary addition until have have the System Bus */

	DECLARE @FilingObjectName NVARCHAR(250),
			@FilingLocation	  NVARCHAR(MAX);

	SELECT	@FilingLocation =
		 (
			 SELECT ss.SiteIdentifier,
					spf.FolderPath
			 FROM	SCore.ObjectSharePointFolder AS spf
			 JOIN	SCore.SharepointSites		 AS ss ON (ss.ID = spf.SharepointSiteId)
			 WHERE	(spf.ObjectGuid = @Guid)
			 FOR JSON PATH
		 );

	DECLARE @QuoteNumberString NVARCHAR(30);

	SELECT	@FilingObjectName  = q.Number + N' ' + p.FormattedAddressComma + N' - ' + client.Name + N' / ' + agent.Name
								 + N' - ' + q.Overview,
			@QuoteNumberString = q.Number
	FROM	SSop.Quotes		AS q
	JOIN	SJob.Properties AS p ON (p.ID			= q.UprnId)
	JOIN	SCrm.Accounts	AS client ON (client.ID = q.ClientAccountId)
	JOIN	SCrm.Accounts	AS agent ON (agent.ID	= q.AgentAccountId)
	WHERE	(q.Guid = @Guid);

	EXEC SOffice.TargetObjectUpsert @EntityTypeGuid = N'1c4794c1-f956-4c32-b886-5500ac778a56',	-- uniqueidentifier
									@RecordGuid = @Guid,										-- uniqueidentifier
									@Number = @QuoteNumberString,								-- bigint
									@Name = @FilingObjectName,									-- nvarchar(250)	
									@FilingLocation = @FilingLocation;
END;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [SSop].[QuotesRevise]
--
GO





CREATE OR ALTER PROCEDURE [SSop].[QuotesRevise] @SourceGuid UNIQUEIDENTIFIER,
								  @TargetGuid UNIQUEIDENTIFIER
AS
BEGIN

	DECLARE @SourceID INT,
			@ID		  INT,
			@IsInsert BIT;

	SELECT	@SourceID = ID
	FROM	SSop.Quotes
	WHERE	(Guid = @SourceGuid);

	IF (@@ROWCOUNT > 1)
	BEGIN
		;
		THROW 60000, N'Invalid source Quote', 1;
	END;

	IF (EXISTS
	 (
		 SELECT 1
		 FROM	SSop.Quotes AS q
		 WHERE	(q.Guid = @SourceGuid)
			AND (q.DateAccepted IS NOT NULL)
	 )
	   )
	BEGIN
		; THROW 60000, N'You cannot revise an accepted quote', 1;
	END;

	EXEC SCore.UpsertDataObject @Guid = @TargetGuid,
								@SchemeName = N'SSop',
								@ObjectName = N'Quotes',
								@IncludeDefaultSecurity = 1,
								@IsInsert = @IsInsert;

	INSERT	SSop.Quotes
		 (RowStatus,
		  Guid,
		  OrganisationalUnitID,
		  QuotingUserId,
		  Number,
		  UprnId,
		  ClientAccountId,
		  ClientAddressId,
		  ClientContactId,
		  ContractID,
		  Date,
		  Overview,
		  ExpiryDate,
		  QuoteSourceId,
		  IsSubjectToNDA,
		  AgentAccountId,
		  AgentAddressId,
		  AgentContactId,
		  ExternalReference,
		  FeeCap,
		  RevisionNumber,
		  OriginalQuoteId,
		  EnquiryServiceID,
		  DescriptionOfWorks,
		  QuotingConsultantId,
		  ExclusionsAndLimitations)
	SELECT	0,
			@TargetGuid,
			q.OrganisationalUnitID,
			q.QuotingUserId,
			q.Number,
			q.UprnId,
			q.ClientAccountId,
			q.ClientAddressId,
			q.ClientContactId,
			q.ContractID,
			GETDATE (),
			q.Overview,
			DATEADD (	MONTH,
						6,
						GETDATE ()
					),
			q.QuoteSourceId,
			q.IsSubjectToNDA,
			q.AgentAccountId,
			q.AgentAddressId,
			q.AgentContactId,
			q.ExternalReference,
			q.FeeCap,
			ISNULL (   latest_revision.rev,
					   0
				   ) + 1,
			CASE
				WHEN q.OriginalQuoteId = (-1) THEN q.ID
				ELSE q.OriginalQuoteId
			END,
			q.EnquiryServiceID,
			q.DescriptionOfWorks,
			q.QuotingConsultantId,
			q.ExclusionsAndLimitations
	FROM	SSop.Quotes AS q
	OUTER APPLY
			(
				SELECT	MAX (q1.RevisionNumber) AS rev
				FROM	SSop.Quotes AS q1
				WHERE	(q1.OriginalQuoteId = CASE
												  WHEN q.OriginalQuoteId = (-1) THEN q.ID
												  ELSE q.OriginalQuoteId
											  END
						)
			)			AS latest_revision
	WHERE	(q.ID = @SourceID);

	SELECT	@ID = SCOPE_IDENTITY ();


	-- Build the collection of items to duplicate. 
	DECLARE @QuoteItems SCore.TwoGuidUniqueList;

	INSERT	@QuoteItems
		 (GuidValue, GuidValueTwo)
	SELECT	qi.Guid,
			NEWID ()
	FROM	SSop.QuoteItems AS qi
	WHERE	(qi.QuoteId = @SourceID)
		AND (qi.RowStatus NOT IN (0, 254));

	-- Build the collection of payment stages to duplicate
	DECLARE @QuotePaymentStages SCore.TwoGuidUniqueList;

	INSERT	@QuotePaymentStages
		 (GuidValue, GuidValueTwo)
	SELECT	qps.Guid,
			NEWID ()
	FROM	SSop.QuotePaymentStages AS qps
	WHERE	(qps.QuoteId = @SourceID)
		AND (qps.RowStatus NOT IN (0, 254));

	-- Build the collection of quote memos
	DECLARE @QuoteMemos SCore.TwoGuidUniqueList;

	INSERT	@QuoteMemos --RETURNS NOTHING
		 (GuidValue, GuidValueTwo)
	SELECT	qm.Guid,
			NEWID ()
	FROM	SSop.QuoteMemos AS qm
	WHERE	(qm.QuoteID = @SourceID)
		AND (qm.RowStatus NOT IN (0, 254));

	-- Create the data objects. 
	DECLARE @NewGuidList SCore.GuidUniqueList;

	INSERT	@NewGuidList
		 (GuidValue)
	SELECT	GuidValueTwo
	FROM	@QuoteItems;

	EXEC SCore.DataObjectBulkUpsert @GuidList = @NewGuidList,		-- GuidUniqueList
									@SchemeName = N'SSop',			-- nvarchar(255)
									@ObjectName = N'QuoteItems',	-- nvarchar(255)
									@IsInsert = @IsInsert OUTPUT;	-- bit	

	DELETE	FROM @NewGuidList;
	INSERT	@NewGuidList
		 (GuidValue)
	SELECT	GuidValueTwo
	FROM	@QuotePaymentStages;

	EXEC SCore.DataObjectBulkUpsert @GuidList = @NewGuidList,				-- GuidUniqueList
									@SchemeName = N'SSop',					-- nvarchar(255)
									@ObjectName = N'QuotePaymentStages',	-- nvarchar(255)
									@IsInsert = @IsInsert OUTPUT;			-- bit	

	DELETE	FROM @NewGuidList;
	INSERT	@NewGuidList
		 (GuidValue)
	SELECT	qm.GuidValueTwo
	FROM	@QuoteMemos AS qm;

	EXEC SCore.DataObjectBulkUpsert @GuidList = @NewGuidList,		-- GuidUniqueList
									@SchemeName = N'SSop',			-- nvarchar(255)
									@ObjectName = N'QuoteMemos',	-- nvarchar(255)
									@IsInsert = @IsInsert OUTPUT;	-- bit	

	-- Duplicate the Quote Items. 
	INSERT	SSop.QuoteItems
		 (RowStatus, Guid, QuoteId, ProductId, Details, Net, VatRate, DoNotConsolidateJob, SortOrder, Quantity)
	SELECT	1,
			qil.GuidValueTwo,
			@ID,
			qi.ProductId,
			qi.Details,
			qi.Net,
			qi.VatRate,
			qi.DoNotConsolidateJob,
			qi.SortOrder,
			qi.Quantity
	FROM	SSop.QuoteItems	   AS qi
	JOIN	@QuoteItems		   AS qil ON (qil.GuidValue = qi.Guid)
	JOIN	SSop.QuoteSections AS oqs ON (oqs.ID		= qi.QuoteSectionId);


	-- Duplicate the Quote Payment Stages 
	INSERT INTO SSop.QuotePaymentStages
		 (RowStatus, Guid, QuoteId, PaymentFrequencyTypeId, PaymentFrequency, Value, PercentageOfTotal, PayAfterStageId)
	SELECT	1,
			qpsl.GuidValueTwo,
			@ID,
			qps.PaymentFrequencyTypeId,
			qps.PaymentFrequency,
			qps.Value,
			qps.PercentageOfTotal,
			qps.PayAfterStageId
	FROM	SSop.QuotePaymentStages AS qps
	JOIN	@QuotePaymentStages		AS qpsl ON (qps.Guid = qpsl.GuidValue);

	-- Duplicate the Quote Memos
	INSERT INTO SSop.QuoteMemos
		 (RowStatus, Guid, QuoteID, Memo, CreatedDateTimeUTC, CreatedByUserId)
	SELECT	1,
			qms.GuidValueTwo,
			@ID,
			qm.Memo,
			qm.CreatedDateTimeUTC,
			qm.CreatedByUserId
	FROM	SSop.QuoteMemos AS qm
	JOIN	@QuoteMemos		AS qms ON (qm.Guid = qms.GuidValue);

	UPDATE	SSop.Quotes
	SET		RowStatus = 1
	WHERE	(ID = @ID);
END;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [SSop].[QuotesDuplicate]
--
GO




CREATE OR ALTER PROCEDURE [SSop].[QuotesDuplicate] @SourceGuid UNIQUEIDENTIFIER,
									 @TargetGuid UNIQUEIDENTIFIER
AS
BEGIN

	DECLARE @SourceID INT,
			@ID		  INT,
			@IsInsert BIT;

	SELECT	@SourceID = ID
	FROM	SSop.Quotes
	WHERE	(Guid = @SourceGuid);

	IF (@@ROWCOUNT > 1)
	BEGIN
		;
		THROW 60000, N'Invalid source Quote', 1;
	END;

	EXEC SCore.UpsertDataObject @Guid = @TargetGuid,
								@SchemeName = N'SSop',
								@ObjectName = N'Quotes',
								@IncludeDefaultSecurity = 1,
								@IsInsert = @IsInsert;

	INSERT	SSop.Quotes
		 (RowStatus,
		  Guid,
		  OrganisationalUnitID,
		  QuotingUserId,
		  Number,
		  UprnId,
		  ClientAccountId,
		  ClientAddressId,
		  ClientContactId,
		  ContractID,
		  Date,
		  Overview,
		  ExpiryDate,
		  QuoteSourceId,
		  IsSubjectToNDA,
		  AgentAccountId,
		  AgentAddressId,
		  AgentContactId,
		  ExternalReference,
		  FeeCap,
		  EnquiryServiceID,
		  ProjectId,
		  DescriptionOfWorks,
		  QuotingConsultantId,
		  ExclusionsAndLimitations)
	SELECT	0,
			@TargetGuid,
			q.OrganisationalUnitID,
			q.QuotingUserId,
			N'0',
			q.UprnId,
			q.ClientAccountId,
			q.ClientAddressId,
			q.ClientContactId,
			q.ContractID,
			GETDATE (),
			q.Overview,
			DATEADD (	MONTH,
						6,
						GETDATE ()
					),
			q.QuoteSourceId,
			q.IsSubjectToNDA,
			q.AgentAccountId,
			q.AgentAddressId,
			q.AgentContactId,
			q.ExternalReference,
			q.FeeCap,
			q.EnquiryServiceID,
			q.ProjectId,
			q.DescriptionOfWorks,
			q.QuotingConsultantId,
			q.ExclusionsAndLimitations
	FROM	SSop.Quotes AS q
	WHERE	(q.ID = @SourceID);

	SELECT	@ID = SCOPE_IDENTITY ();



	-- Build the collection of items to duplicate. 
	DECLARE @QuoteItems SCore.TwoGuidUniqueList;

	INSERT	@QuoteItems
		 (GuidValue, GuidValueTwo)
	SELECT	qi.Guid,
			NEWID ()
	FROM	SSop.QuoteItems AS qi
	WHERE	(qi.QuoteId = @SourceID) --CBLD-613
		AND (qi.RowStatus NOT IN (0, 254));


	-- Build the collection of payment stages to duplicate
	DECLARE @QuotePaymentStages SCore.TwoGuidUniqueList;

	INSERT	@QuotePaymentStages --RETURNS NOTHING
		 (GuidValue, GuidValueTwo)
	SELECT	qps.Guid,
			NEWID ()
	FROM	SSop.QuotePaymentStages AS qps
	WHERE	(qps.QuoteId = @SourceID)
		AND (qps.RowStatus NOT IN (0, 254));


	-- Build the collection of quote memos
	DECLARE @QuoteMemos SCore.TwoGuidUniqueList;

	INSERT	@QuoteMemos --RETURNS NOTHING
		 (GuidValue, GuidValueTwo)
	SELECT	qm.Guid,
			NEWID ()
	FROM	SSop.QuoteMemos AS qm
	WHERE	(qm.QuoteID = @SourceID)
		AND (qm.RowStatus NOT IN (0, 254));

	-- Create the data objects. 
	DECLARE @NewGuidList SCore.GuidUniqueList;


	INSERT	@NewGuidList
		 (GuidValue)
	SELECT	GuidValueTwo
	FROM	@QuoteItems;

	EXEC SCore.DataObjectBulkUpsert @GuidList = @NewGuidList,		-- GuidUniqueList
									@SchemeName = N'SSop',			-- nvarchar(255)
									@ObjectName = N'QuoteItems',	-- nvarchar(255)
									@IsInsert = @IsInsert OUTPUT;	-- bit	

	DELETE	FROM @NewGuidList;
	INSERT	@NewGuidList
		 (GuidValue)
	SELECT	GuidValueTwo
	FROM	@QuotePaymentStages;

	EXEC SCore.DataObjectBulkUpsert @GuidList = @NewGuidList,				-- GuidUniqueList
									@SchemeName = N'SSop',					-- nvarchar(255)
									@ObjectName = N'QuotePaymentStages',	-- nvarchar(255)
									@IsInsert = @IsInsert OUTPUT;			-- bit	

	DELETE	FROM @NewGuidList;
	INSERT	@NewGuidList
		 (GuidValue)
	SELECT	qm.GuidValueTwo
	FROM	@QuoteMemos AS qm;

	EXEC SCore.DataObjectBulkUpsert @GuidList = @NewGuidList,		-- GuidUniqueList
									@SchemeName = N'SSop',			-- nvarchar(255)
									@ObjectName = N'QuoteMemos',	-- nvarchar(255)
									@IsInsert = @IsInsert OUTPUT;	-- bit	


	-- Duplicate the Quote Items. 
	INSERT	SSop.QuoteItems
		 (RowStatus, Guid, QuoteId, ProductId, Details, Net, VatRate, DoNotConsolidateJob, SortOrder, Quantity)
	SELECT	1,
			qil.GuidValueTwo,
			@ID,
			qi.ProductId,
			qi.Details,
			qi.Net,
			qi.VatRate,
			qi.DoNotConsolidateJob,
			qi.SortOrder,
			qi.Quantity
	FROM	SSop.QuoteItems AS qi
	JOIN	@QuoteItems		AS qil ON (qil.GuidValue = qi.Guid);



	-- Duplicate the Quote Payment Stages 
	INSERT INTO SSop.QuotePaymentStages
		 (RowStatus, Guid, QuoteId, PaymentFrequencyTypeId, PaymentFrequency, Value, PercentageOfTotal, PayAfterStageId)
	SELECT	1,
			qpsl.GuidValueTwo,
			@ID,
			qps.PaymentFrequencyTypeId,
			qps.PaymentFrequency,
			qps.Value,
			qps.PercentageOfTotal,
			qps.PayAfterStageId
	FROM	SSop.QuotePaymentStages AS qps
	JOIN	@QuotePaymentStages		AS qpsl ON (qps.Guid = qpsl.GuidValue);


	-- Duplicate the Quote Memos
	INSERT INTO SSop.QuoteMemos
		 (RowStatus, Guid, QuoteID, Memo, CreatedDateTimeUTC, CreatedByUserId)
	SELECT	1,
			qms.GuidValueTwo,
			@ID,
			qm.Memo,
			qm.CreatedDateTimeUTC,
			qm.CreatedByUserId
	FROM	SSop.QuoteMemos AS qm
	JOIN	@QuoteMemos		AS qms ON (qm.Guid = qms.GuidValue);


	-- Allocate a new Quote number. 

	DECLARE @QuoteNumber NVARCHAR(30);

	SELECT	@QuoteNumber = NEXT VALUE FOR SSop.QuoteNumber;

	UPDATE	SSop.Quotes
	SET		Number = @QuoteNumber,
			RowStatus = 1
	WHERE	(ID = @ID);
END;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SSop].[EnquiryService_ExtendedInfo]
--
GO









CREATE OR ALTER VIEW	[SSop].[EnquiryService_ExtendedInfo]
    --WITH SCHEMABINDING
AS
SELECT	es.Id,
		es.RowStatus,
		es.RowVersion,
		es.Guid,
		ISNULL(quote.QuoteID, -1) AS QuoteID,
		quote.DateAccepted,
		quote.DateSent,
		quote.DateRejected,
		quote.QuoteNet,
		ISNULL(quote.Number, 0) AS Number,
		ISNULL(Quote.RevisionNumber, 0) AS RevisionNumber,
		quote.DateDeclinedToQuote AS DeclinedToQuoteDate, --[CBLD-592]
		quote.DeclinedToQuoteReason AS DeclinedToQuoteReason
FROM	SSop.EnquiryServices es
OUTER APPLY 
	(
		SELECT	q.ID AS QuoteID,
				q.DateAccepted,
				q.DateSent, 
				q.DateRejected,
				q.DateDeclinedToQuote, -- [CBLD-592]
				q.DeclinedToQuoteReason,
				q.Number,
				q.RevisionNumber,
				QuoteLines.Net QuoteNet
		FROM	SSop.Quotes AS q
		OUTER APPLY (
			SELECT	SUM(qit.LineNet) AS Net
			FROM	SSop.QuoteItems AS qi 
			JOIN	SSop.QuoteItemTotals AS qit ON (qit.ID = qi.ID)
			WHERE	(qi.QuoteId = q.ID)
				AND	(qi.RowStatus NOT IN (0, 254))
		) QuoteLines
		WHERE	(q.EnquiryServiceID = es.ID)
			AND	(q.EnquiryServiceID > -1)
			AND	(NOT EXISTS
					(
						SELECT	1
						FROM	SSop.Quotes AS q2
						WHERE	(q2.EnquiryServiceID = q.EnquiryServiceID)
							AND	(q2.RevisionNumber > q.RevisionNumber)
							AND	(q2.ID <> q.ID)
					)
				)
	) AS Quote
----[CBLD-592: Getting the declined to quote date]
--OUTER APPLY
--	(
--		SELECT en.DateDeclinedToQuote 
--		FROM SSop.Quotes AS en
--		WHERE es.EnquiryId = en.ID
--	) AS Enquiry

GO
